# Target Sum — O(n * sum) time with memoization
# KEY INSIGHT: DFS(index, remaining_sum) = ways to assign signs

def findTargetSumWays(nums, target):
    memo = {}

    def dfs(i, remaining):
        if i == len(nums):
            return 1 if remaining == 0 else 0
        if (i, remaining) in memo:
            return memo[(i, remaining)]

        # Add or subtract current number
        add = dfs(i + 1, remaining - nums[i])
        sub = dfs(i + 1, remaining + nums[i])
        memo[(i, remaining)] = add + sub
        return memo[(i, remaining)]

    return dfs(0, target)
# SUBSET-SUM REDUCTION: P - N = target, P + N = total
# → P = (total + target) / 2, find subsets summing to P
